SELECT COUNT(*) FROM (SELECT T.PK_PAUTA FROM TURMA T JOIN SERVIDOR S ON S.PK_SIAPE = T.FK_SERVIDOR JOIN DISCIPLINA_CURSO DC ON DC.PK = T.FK_DISCIPLINA_CURSO JOIN CURSO C ON C.PK = DC.FK_CURSO WHERE COALESCE(T.DATA_INICIO, T.DATA_FIM) >= DATE('now', '-5 years') AND LOWER(C.NIVEL) = LOWER('superior') AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('inh') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%administracao%') UNION ALL SELECT T.PK_PAUTA FROM TURMA T JOIN SERVIDOR S ON S.PK_SIAPE = T.FK_SERVIDOR_AUX JOIN DISCIPLINA_CURSO DC ON DC.PK = T.FK_DISCIPLINA_CURSO JOIN CURSO C ON C.PK = DC.FK_CURSO WHERE T.FK_SERVIDOR_AUX IS NOT NULL AND COALESCE(T.DATA_INICIO, T.DATA_FIM) >= DATE('now', '-5 years') AND LOWER(C.NIVEL) = LOWER('superior') AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('inh') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%administracao%')) X